final:
module RefModule(
   input                clk ,
   input                rst_n,
   input  [15:0]        limit,

   output reg [15:0]    Q  
);
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always@(posedge clk or negedge rst_n or posedge dbg_halt)begin
        if(!rst_n) Q <= 16'd0;
        else if(Q < limit) Q <= Q + 16'd1;
    end
endmodule
